<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***Endpoint-to-Endpoint(E2E)CommunicationLayer*StandardizedinternalAPIcommunicationbetweenendpoints*/classE2EClient{private$baseURL;private$timeout;publicfunction__construct(){$this->baseURL=BASE_URL;$this->timeout=30;}/***MakeinternalAPIcall*/publicfunctionrequest($endpoint,$options=[]){$method=$options['method']??'GET';$data=$options['data']??null;$headers=$options['headers']??[];$timeout=$options['timeout']??$this->timeout;$url=$this->baseURL.$endpoint;$ch=curl_init();curl_setopt_array($ch,[CURLOPT_URL=>$url,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>$timeout,CURLOPT_CUSTOMREQUEST=>$method,CURLOPT_HTTPHEADER=>array_merge(['Content-Type:application/json','X-Internal-API:1','X-Request-ID:'.uniqid('e2e_',true)],$headers),CURLOPT_SSL_VERIFYPEER=>false,CURLOPT_SSL_VERIFYHOST=>false]);if($data&&$method!=='GET'){if(is_array($data)||is_object($data)){$data=json_encode($data);}curl_setopt($ch,CURLOPT_POSTFIELDS,$data);}$response=curl_exec($ch);$httpCode=curl_getinfo($ch,CURLINFO_HTTP_CODE);$error=curl_error($ch);curl_close($ch);if($error){thrownewException("E2ERequestError:$error");}if($httpCode>=400){thrownewException("E2EHTTPError:$httpCode");}returnjson_decode($response,true);}/***GETrequest*/publicfunctionget($endpoint,$params=[]){if(!empty($params)){$endpoint.='?'.http_build_query($params);}return$this->request($endpoint,['method'=>'GET']);}/***POSTrequest*/publicfunctionpost($endpoint,$data=[]){return$this->request($endpoint,['method'=>'POST','data'=>$data]);}/***PUTrequest*/publicfunctionput($endpoint,$data=[]){return$this->request($endpoint,['method'=>'PUT','data'=>$data]);}/***DELETErequest*/publicfunctiondelete($endpoint,$data=[]){return$this->request($endpoint,['method'=>'DELETE','data'=>$data]);}}/***E2EServiceRegistry*Managesinternalservicecommunication*/classE2EServiceRegistry{privatestatic$services=[];privatestatic$client=null;publicstaticfunctiongetClient(){if(self::$client===null){self::$client=newE2EClient();}returnself::$client;}/***Registeraservice*/publicstaticfunctionregister($name,$endpoint,$options=[]){self::$services[$name]=['endpoint'=>$endpoint,'options'=>$options];}/***Callaregisteredservice*/publicstaticfunctioncall($service,$action,$data=[]){if(!isset(self::$services[$service])){thrownewException("Service'$service'notregistered");}$serviceConfig=self::$services[$service];$endpoint=$serviceConfig['endpoint'];$options=$serviceConfig['options'];/Addactiontodataif(is_array($data)){$data['action']=$action;}else{$data=['action'=>$action,'data'=>$data];}$method=$options['method']??'POST';returnself::getClient()->request($endpoint,['method'=>$method,'data'=>$data]);}/***Getpersonildatafrompersonilservice*/publicstaticfunctiongetPersonil($filters=[]){returnself::getClient()->get('/api/personil_list.php',$filters);}/***Getunsurdatafromunsurservice*/publicstaticfunctiongetUnsur($filters=[]){returnself::getClient()->get('/api/unsur_crud.php',array_merge(['action'=>'list'],$filters));}/***Getbagiandatafrombagianservice*/publicstaticfunctiongetBagian($filters=[]){returnself::getClient()->get('/api/bagian_crud.php',array_merge(['action'=>'list'],$filters));}/***Getjabatandatafromjabatanservice*/publicstaticfunctiongetJabatan($filters=[]){returnself::getClient()->get('/api/jabatan_crud.php',array_merge(['action'=>'list'],$filters));}/***Getstatisticsfrommultipleservices*/publicstaticfunctiongetStatistics(){$client=self::getClient();$promises=['personil'=>$client->get('/api/personil_list.php',['per_page'=>1]),'unsur'=>$client->get('/api/unsur_stats.php'),'bagian'=>$client->get('/api/bagian_crud.php',['action'=>'list']),'jabatan'=>$client->get('/api/jabatan_crud.php',['action'=>'list'])];return$promises;}/***Validatedataconsistencyacrossservices*/publicstaticfunctionvalidateDataConsistency(){$client=self::getClient();try{/Getdatafromallservices$personil=$client->get('/api/personil_list.php',['per_page'=>1000]);$unsur=$client->get('/api/unsur_crud.php',['action'=>'list']);$bagian=$client->get('/api/bagian_crud.php',['action'=>'list']);$jabatan=$client->get('/api/jabatan_crud.php',['action'=>'list']);$issues=[];/Checkfororphanedrecordsif($personil['success']&&$unsur['success']&&$bagian['success']&&$jabatan['success']){$unsurIds=array_column($unsur['data'],'id');$bagianIds=array_column($bagian['data'],'id');$jabatanIds=array_column($jabatan['data'],'id');forforeach($personil['data']as$person){/Checkunsurreferenceif($person['unsur_id']&&!in_array($person['unsur_id'],$unsurIds)){$issues[]=['type'=>'orphaned_unsur','personil_id'=>$person['id'],'unsur_id'=>$person['unsur_id'],'message'=>"Personil{$person['nama']}referencesnon-existentunsur{$person['unsur_id']}"];}/Checkbagianreferenceif($person['bagian_id']&&!in_array($person['bagian_id'],$bagianIds)){$issues[]=['type'=>'orphaned_bagian','personil_id'=>$person['id'],'bagian_id'=>$person['bagian_id'],'message'=>"Personil{$person['nama']}referencesnon-existentbagian{$person['bagian_id']}"];}/Checkjabatanreferenceif($person['jabatan_id']&&!in_array($person['jabatan_id'],$jabatanIds)){$issues[]=['type'=>'orphaned_jabatan','personil_id'=>$person['id'],'jabatan_id'=>$person['jabatan_id'],'message'=>"Personil{$person['nama']}referencesnon-existentjabatan{$person['jabatan_id']}"];}}}return['success'=>true,'issues'=>$issues,'timestamp'=>date('c')];}catch(Exception$e){return['success'=>false,'error'=>$e->getMessage(),'timestamp'=>date('c')];}}/***Syncdatabetweenservices*/publicstaticfunctionsyncData($source,$target,$data){$client=self::getClient();try{/Getcurrentdatafromtarget$currentData=$client->get($target,['action'=>'list']);if(!$currentData['success']){thrownewException("Failedtogetcurrentdatafromtarget:{$target}");}$synced=[];$errors=[];forforeach($dataas$item){try{/Checkifitemexistsintarget$exists=false;forforeach($currentData['data']as$existing){if($existing['id']==$item['id']){$exists=true;break;}}if($exists){/Updateexistingitem$result=$client->put($target,array_merge($item,['action'=>'update']));}else{/Createnewitem$result=$client->post($target,array_merge($item,['action'=>'create']));}if($result['success']){$synced[]=$item['id'];}else{$errors[]=['id'=>$item['id'],'error'=>$result['message']];}}catch(Exception$e){$errors[]=['id'=>$item['id'],'error'=>$e->getMessage()];}}return['success'=>true,'synced'=>$synced,'errors'=>$errors,'timestamp'=>date('c')];}catch(Exception$e){return['success'=>false,'error'=>$e->getMessage(),'timestamp'=>date('c')];}}}/Auto-registercommonservicesE2EServiceRegistry::register('personil','/api/personil_list.php',['method'=>'GET']);E2EServiceRegistry::register('unsur','/api/unsur_crud.php',['method'=>'POST']);E2EServiceRegistry::register('bagian','/api/bagian_crud.php',['method'=>'POST']);E2EServiceRegistry::register('jabatan','/api/jabatan_crud.php',['method'=>'POST']);E2EServiceRegistry::register('user','/api/user_management.php',['method'=>'POST']);E2EServiceRegistry::register('backup','/api/backup_api.php',['method'=>'POST']);/HelperfunctionsforcommonE2EoperationsfunctionvalidateE2EData(){returnE2EServiceRegistry::validateDataConsistency();}functiongetE2EStatistics(){returnE2EServiceRegistry::getStatistics();}functionsyncE2EData($source,$target,$data){returnE2EServiceRegistry::syncData($source,$target,$data);}?>
